"use client";

import React from "react";
import { Modal } from "@/components/ui/modal";
import Button from "@/components/ui/button/Button";
import Input from "@/components/form/input/InputField";
import Label from "@/components/form/Label";
import type { Customer, CustomerForm } from "./CustomersClient";

type Props = {
  isOpen: boolean;
  onClose: () => void;
  editingCustomer: Customer | null;
  form: CustomerForm;
  setForm: React.Dispatch<React.SetStateAction<CustomerForm>>;
  onSubmit: (e: React.FormEvent) => void;
  superAdmin: boolean;
};

export default function CustomerModal({
  isOpen,
  onClose,
  editingCustomer,
  form,
  setForm,
  onSubmit,
  superAdmin,
}: Props) {
  return (
    <Modal isOpen={isOpen} onClose={onClose} className="max-w-[700px] m-4">
      <div className="no-scrollbar relative w-full max-w-[700px] overflow-y-auto rounded-3xl bg-white p-4 dark:bg-gray-900 lg:p-11">
        <div className="px-2 pr-14">
          <h4 className="mb-2 text-2xl font-semibold text-gray-800 dark:text-white/90">
            {editingCustomer ? "Edit Customer" : "Add Customer"}
          </h4>

          <p className="mb-6 text-sm text-gray-500 dark:text-gray-400 lg:mb-7">
            أدخل معلومات الزبون
          </p>
        </div>

        {superAdmin && !editingCustomer && (
          <div className="mb-5 rounded-lg border border-warning-200 bg-warning-50 px-4 py-3 text-sm text-warning-700 dark:border-warning-500/30 dark:bg-warning-500/10 dark:text-warning-400">
            ⚠️ Super admin can view customers, but customer creation should
            normally be done by merchants.
          </div>
        )}

      <form
  key={editingCustomer?.id || "new-customer"}
  onSubmit={onSubmit}
  className="flex flex-col"
>
          <div className="custom-scrollbar max-h-[450px] overflow-y-auto px-2 pb-3">
            <h5 className="mb-5 text-lg font-medium text-gray-800 dark:text-white/90 lg:mb-6">
              معلومات الزبائن
            </h5>

            <div className="grid grid-cols-1 gap-x-6 gap-y-5 lg:grid-cols-2">
              <div>
                <Label>الاسم الكامل</Label>
                <Input
                  type="text"
                  defaultValue={form.full_name_ar}
                  onChange={(e) =>
                    setForm({ ...form, full_name_ar: e.target.value })
                  }
                  required
                />
              </div>

              <div>
                <Label>English Name</Label>
                <Input
                  type="text"
                  defaultValue={form.full_name_en}
                  onChange={(e) =>
                    setForm({ ...form, full_name_en: e.target.value })
                  }
                />
              </div>

              <div>
                <Label>رقم الموبايل</Label>
                <Input
                  type="text"
                  defaultValue={form.mobile_number}
                  onChange={(e) =>
                    setForm({ ...form, mobile_number: e.target.value })
                  }
                  required
                />
              </div>

              <div>
                <Label>الرقم الوطني</Label>
                <Input
                  type="text"
                  defaultValue={form.national_id}
                  onChange={(e) =>
                    setForm({ ...form, national_id: e.target.value })
                  }
                />
              </div>

              <div>
                <Label>المدينة</Label>
                <Input
                  type="text"
                  defaultValue={form.city}
                  onChange={(e) => setForm({ ...form, city: e.target.value })}
                />
              </div>

              <div>
                <Label>العنوان</Label>
                <Input
                  type="text"
                  defaultValue={form.address}
                  onChange={(e) =>
                    setForm({ ...form, address: e.target.value })
                  }
                />
              </div>
            </div>
          </div>

          <div className="flex items-center gap-3 px-2 mt-6 lg:justify-end">
            <Button size="sm" variant="outline" type="button" onClick={onClose}>
              إلغاء
            </Button>

            <Button size="sm" type="submit">
              {editingCustomer ? "حفظ" : "إضافة"}
            </Button>
          </div>
        </form>
      </div>
    </Modal>
  );
}