"use client";

import React, { useEffect, useState } from "react";
import ComponentCard from "@/components/common/ComponentCard";
import PageBreadcrumb from "@/components/common/PageBreadCrumb";
import { apiFetch } from "@/lib/api";
import { isSuperAdmin } from "@/lib/auth";
import CustomersTable from "./CustomersTable";
import CustomerModal from "./CustomerModal";

export type Customer = {
  id: string;
  full_name_ar: string;
  full_name_en?: string;
  mobile_number: string;
  national_id?: string;
  city?: string;
  address?: string;
  risk_level?: string;
  status?: string;
};

export type CustomerForm = {
  full_name_ar: string;
  full_name_en: string;
  mobile_number: string;
  national_id: string;
  city: string;
  address: string;
};

const emptyForm: CustomerForm = {
  full_name_ar: "",
  full_name_en: "",
  mobile_number: "",
  national_id: "",
  city: "",
  address: "",
};

export default function CustomersClient() {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [page, setPage] = useState(1);
  const pageSize = 15;

  const [isOpen, setIsOpen] = useState(false);
  const [editingCustomer, setEditingCustomer] = useState<Customer | null>(null);
  const [superAdmin, setSuperAdmin] = useState(false);
  const [form, setForm] = useState<CustomerForm>(emptyForm);

  useEffect(() => {
    loadCustomers();
    setSuperAdmin(isSuperAdmin());
  }, []);

  async function loadCustomers() {
    try {
      setLoading(true);
      setError("");
      const data = await apiFetch("/merchant/customers");
      setCustomers(data);
    } catch (err: any) {
      setError(err.message || "Failed to load customers");
    } finally {
      setLoading(false);
    }
  }

  function openAddModal() {
    setEditingCustomer(null);
    setForm(emptyForm);
    setIsOpen(true);
  }

  function openEditModal(customer: Customer) {
    setEditingCustomer(customer);
    setForm({
      full_name_ar: customer.full_name_ar || "",
      full_name_en: customer.full_name_en || "",
      mobile_number: customer.mobile_number || "",
      national_id: customer.national_id || "",
      city: customer.city || "",
      address: customer.address || "",
    });
    setIsOpen(true);
  }

  function closeModal() {
    setIsOpen(false);
    setEditingCustomer(null);
    setForm(emptyForm);
  }

  async function saveCustomer(e: React.FormEvent) {
    e.preventDefault();

    try {
      setError("");

      if (editingCustomer) {
        await apiFetch(`/merchant/customers/${editingCustomer.id}`, {
          method: "PATCH",
          body: JSON.stringify(form),
        });
      } else {
        await apiFetch("/merchant/customers", {
          method: "POST",
          body: JSON.stringify(form),
        });
      }

      closeModal();
      await loadCustomers();
    } catch (err: any) {
      setError(err.message || "Failed to save customer");
    }
  }

  async function deactivateCustomer(id: string) {
    if (!confirm("Deactivate this customer?")) return;

    try {
      setError("");

      await apiFetch(`/merchant/customers/${id}`, {
        method: "DELETE",
      });

      await loadCustomers();
    } catch (err: any) {
      setError(err.message || "Failed to deactivate customer");
    }
  }

  const totalPages = Math.ceil(customers.length / pageSize);

  const paginatedCustomers = customers.slice(
    (page - 1) * pageSize,
    page * pageSize
  );

  return (
    <div>
      <PageBreadcrumb pageTitle="الزبائن" />

      <div className="space-y-6">
        <ComponentCard>
          <div className="mb-5 flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <div>
              <h4 className="text-lg font-semibold text-gray-800 dark:text-white/90">
                سجل الزبائن
              </h4>
              <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">
               هنا يمكنك إضافة أو تعديل زبائن 
              </p>
            </div>

            <button
              onClick={openAddModal}
              className="inline-flex items-center justify-center rounded-lg bg-brand-500 px-4 py-2.5 text-sm font-medium text-white hover:bg-brand-600"
            >
              إضافة زبون
            </button>
          </div>

          {error && (
            <div className="mb-5 rounded-lg border border-error-200 bg-error-50 px-4 py-3 text-sm text-error-700 dark:border-error-500/30 dark:bg-error-500/10 dark:text-error-400">
              {error}
            </div>
          )}

          <CustomersTable
            customers={paginatedCustomers}
            loading={loading}
            onEdit={openEditModal}
            onDeactivate={deactivateCustomer}
          />

          <div className="mt-4 flex items-center justify-between">
            <button
              onClick={() => setPage((p) => Math.max(p - 1, 1))}
              disabled={page === 1}
              className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
            >
              Previous
            </button>

            <span className="text-sm text-gray-500 dark:text-gray-400">
              Page {page} of {totalPages || 1}
            </span>

            <button
              onClick={() => setPage((p) => Math.min(p + 1, totalPages))}
              disabled={page === totalPages || totalPages === 0}
              className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
            >
              Next
            </button>
          </div>
        </ComponentCard>
      </div>

      <CustomerModal
        isOpen={isOpen}
        onClose={closeModal}
        editingCustomer={editingCustomer}
        form={form}
        setForm={setForm}
        onSubmit={saveCustomer}
        superAdmin={superAdmin}
      />
    </div>
  );
}